let raw;
try {
  raw = typeof $input.first().json.body === 'string'
    ? JSON.parse($input.first().json.body)
    : ($input.first().json.body || $input.first().json);
} catch(e) { raw = $input.first().json; }

const meta = raw.meta  || {};
const m1   = raw.modulo_1_configuracion         || {};
const m1b  = raw.modulo_1b_documentos_por_proceso || {};
const m2b  = raw.modulo_2b_severidad_consolidada  || {};
const m4   = raw.modulo_4_responsables            || {};
const m4b  = raw.modulo_4b_flujos_revision        || {};
const m5   = raw.modulo_5_observaciones           || {};

// ── Procesos estándar ──
const evalTypes  = m1.tiposEvaluacion || {};
const matriz     = m1.matrizProcesoArea || [];
const customProc = (m1.procesosPersonalizados || []).filter(p => p.activo);
const PROC_MAP   = { express:'spot', completa:'general', reforzada:'critico', internacional:'internacional', subcontratacion:'subcontratacion' };
const PROC_NOMBRES = { express:'Proveedor Spot', completa:'Proveedor General', reforzada:'Proveedor Crítico', internacional:'Proveedor Internacional', subcontratacion:'Subcontratación' };

const procCols = {};
Object.entries(PROC_MAP).forEach(([key, slug]) => {
  const activo = !!evalTypes[key]?.activo;
  procCols[`proceso_${slug}_activo`] = activo ? 'sí' : 'no';
  const row = matriz.find(r => r.proceso === PROC_NOMBRES[key]);
  procCols[`proceso_${slug}_areas`] = activo && row
    ? Object.entries(row.areas).filter(([,v]) => v).map(([a]) => a).join(', ')
    : '';
});
procCols.procesos_custom_nombres = customProc.map(p => p.nombre).join(', ');
procCols.procesos_custom_areas   = customProc.map(p => {
  const row = matriz.find(r => r.proceso === p.nombre);
  return row ? Object.entries(row.areas).filter(([,v]) => v).map(([a]) => a).join(', ') : '';
}).join(' | ');

// ── Documentos por proceso ──
const docsPP  = m1b.porProceso || [];
const docCols = {};
const SLUG_PROC = { 'Proveedor Spot':'spot', 'Proveedor General':'general', 'Proveedor Crítico':'critico', 'Proveedor Internacional':'internacional', 'Subcontratación':'subcontratacion' };
Object.entries(SLUG_PROC).forEach(([nombre, slug]) => {
  const proc = docsPP.find(p => p.proceso === nombre);
  docCols[`docs_req_${slug}`] = proc ? proc.documentos.filter(d => d.estado==='requerido').map(d => d.documento).join(', ') : '';
  docCols[`docs_opc_${slug}`] = proc ? proc.documentos.filter(d => d.estado==='opcional').map(d => d.documento).join(', ')  : '';
});
docCols.docs_custom_resumen = customProc.map(p => {
  const req = (p.documentos||[]).filter(d => d.estado==='requerido'||d.estado==='req').map(d=>d.documento).join(', ');
  const opc = (p.documentos||[]).filter(d => d.estado==='opcional' ||d.estado==='opc').map(d=>d.documento).join(', ');
  return `${p.nombre}: req[${req||'ninguno'}] opc[${opc||'ninguno'}]`;
}).join(' | ');

// ── Alertas consolidadas por grupo ──
const alertasAll = m2b.alertas || [];
const porTema    = m4b.porTema || {};
const SEV_RANK   = { leve:0, media:1, grave:2 };
const SEV_ICON   = { leve:'🔵', media:'🟡', grave:'🔴' };
const GROUPS = [
  ['Tributario','tributario'],
  ['Financiero','financiero'],
  ['Legal y Societario','legal_societario'],
  ['Laboral','laboral'],
  ['Cumplimiento','cumplimiento'],
];
const alertCols = {};
GROUPS.forEach(([grupo, slug]) => {
  const activas = alertasAll.filter(a => a.grupo === grupo);
  const maxSev  = activas.reduce((b, a) => SEV_RANK[a.severidadFinal] > SEV_RANK[b] ? a.severidadFinal : b, 'leve');
  const rv      = (porTema[grupo]?.revisores || [])[0];
  alertCols[`alertas_${slug}`]          = activas.map(a => `${a.alerta}(${a.severidadFinal})`).join(', ') || 'ninguna';
  alertCols[`alertas_${slug}_severidad`]= activas.length ? maxSev : '';
  alertCols[`alertas_${slug}_revisor`]  = rv ? (rv.nombre || rv.email || '') : '';
});
const totalActivas = alertasAll.length;
const totalGraves  = alertasAll.filter(a => a.severidadFinal==='grave').length;
const totalMedias  = alertasAll.filter(a => a.severidadFinal==='media').length;
const totalLeves   = alertasAll.filter(a => a.severidadFinal==='leve').length;

// ── Responsables ──
const AREAS  = ['abastecimiento','cumplimiento','finanzas','legal'];
const LABELS = { abastecimiento:'Abastecimiento', cumplimiento:'Cumplimiento', finanzas:'Finanzas', legal:'Legal' };
const porArea  = m4.porArea || {};
const respCols = {};
AREAS.forEach(a => {
  respCols[`resp_${a}_nombre`] = porArea[a]?.encargado?.nombre || '';
  respCols[`resp_${a}_email`]  = porArea[a]?.encargado?.email  || '';
  respCols[`guardado_${a}`]    = porArea[a]?.guardado ? 'sí' : 'no';
});

// ── Notas por área ──
const notasCols = {};
AREAS.forEach(a => { notasCols[`notas_${a}`] = m5.observacionesPorArea?.[a] || ''; });
notasCols.notas_sincronizacion = m5.notasSincronizacion || '';

// ── Slack ──
const fechaFormato = meta.timestamp
  ? new Date(meta.timestamp).toLocaleDateString('es-CL',{day:'2-digit',month:'2-digit',year:'numeric',hour:'2-digit',minute:'2-digit'})
  : '';

const procActivos = [
  ...Object.entries(PROC_MAP).filter(([k]) => evalTypes[k]?.activo).map(([k]) => PROC_NOMBRES[k]),
  ...customProc.map(p => p.nombre),
].join(', ');

const alertasSlack = GROUPS.map(([grupo]) => {
  const activas = alertasAll.filter(a => a.grupo === grupo);
  if (!activas.length) return null;
  const maxSev = activas.reduce((b,a) => SEV_RANK[a.severidadFinal]>SEV_RANK[b]?a.severidadFinal:b,'leve');
  const rv = (porTema[grupo]?.revisores||[])[0];
  const revisor = rv ? (rv.nombre||rv.email||'Sin asignar') : 'Sin asignar';
  return `• ${SEV_ICON[maxSev]} *${grupo}* (${activas.length}) → ${revisor}`;
}).filter(Boolean).join('\n');

const respSlack = AREAS
  .filter(a => respCols[`resp_${a}_nombre`]||respCols[`resp_${a}_email`])
  .map(a => `• *${LABELS[a]}:* ${respCols[`resp_${a}_nombre`]} ${respCols[`resp_${a}_email`]?`(${respCols[`resp_${a}_email`]})`:''}`.trim())
  .join('\n');

const slackMsg = [
  ':clipboard: *Nueva política de DD Proveedores completada*',
  '',
  `*Empresa:* ${meta.empresa||'(sin nombre)'}`,
  `*Email CS:* ${meta.email||'(sin email)'}`,
  `*Fecha:* ${fechaFormato}`,
  `*Áreas:* ${(meta.areasParticipantes||[]).join(', ')}`,
  '',
  `*Procesos activos:* ${procActivos||'Ninguno'}`,
  '',
  totalActivas>0
    ? `*Alertas: ${totalActivas}* (${totalGraves} 🔴 · ${totalMedias} 🟡 · ${totalLeves} 🔵)\n${alertasSlack}`
    : '*Alertas:* ninguna activa',
  '',
  respSlack?`*Responsables:*\n${respSlack}`:'',
  notasCols.notas_sincronizacion?`\n*Notas sync:* _${notasCols.notas_sincronizacion}_`:'',
].filter(s=>s!==undefined).join('\n');

return [{ json: {
  // Identificación
  empresa:            meta.empresa||'',
  email_cs:           meta.email||'',
  timestamp:          meta.timestamp||'',
  session_id:         meta.sessionId||'',
  areas_participantes:(meta.areasParticipantes||[]).join(', '),
  // Procesos
  ...procCols,
  // Documentos por proceso
  ...docCols,
  // Alertas resumen
  alertas_activas_total: totalActivas,
  alertas_graves_total:  totalGraves,
  alertas_medias_total:  totalMedias,
  alertas_leves_total:   totalLeves,
  // Alertas por grupo
  ...alertCols,
  // Responsables
  ...respCols,
  // Notas
  ...notasCols,
  // Slack
  _slack_msg: slackMsg,
}}];
